// ═══════════════════════════════════════════════════════════════════════════
// BETTI SIGNATURE -- the constructive topological primitive
// ═══════════════════════════════════════════════════════════════════════════

/** A topological space characterized by its Betti numbers.
 *  Mirrors MolecularTopology.lean's BettiSignature structure. */
export interface BettiSignature {
  /** β₀: connected components */
  readonly beta0: number;
  /** β₁: independent loops (cycle rank) */
  readonly beta1: number;
  /** β₂: enclosed cavities */
  readonly beta2: number;
}

/** Euler characteristic: χ = β₀ - β₁ + β₂.
 *  Computed, not declared. */
export function eulerCharacteristic(b: BettiSignature): number {
  return b.beta0 - b.beta1 + b.beta2;
}

/** Genus of a closed orientable surface: g = (2 - χ) / 2. */
export function genus(b: BettiSignature): number {
  return (2 - eulerCharacteristic(b)) / 2;
}

/** Topological deficit between computation and transport.
 *  Mirrors CoveringSpaceCausality.lean's topologicalDeficit. */
export function topologicalDeficit(
  computation: BettiSignature,
  transport: BettiSignature
): number {
  return computation.beta1 - transport.beta1;
}

// ═══════════════════════════════════════════════════════════════════════════
// CARRIER SHAPES -- constructed from BettiSignature
// ═══════════════════════════════════════════════════════════════════════════

/** The point: one component, no loops, no cavities. */
export const POINT: BettiSignature = { beta0: 1, beta1: 0, beta2: 0 };

/** The circle: one component, one loop, no cavities. */
export const CIRCLE: BettiSignature = { beta0: 1, beta1: 1, beta2: 0 };

/** The sphere (BATNA carrier): one component, no loops, one cavity. */
export const SPHERE: BettiSignature = { beta0: 1, beta1: 0, beta2: 1 };

/** The torus (WATNA carrier): one component, two loops, one cavity. */
export const TORUS: BettiSignature = { beta0: 1, beta1: 2, beta2: 1 };

/** The headStream (LIVE carrier): topologically a circle. */
export const HEAD_STREAM: BettiSignature = CIRCLE;

/** Consciousness threshold: β₁ ≥ 2. Derived from structure comparison. */
export const CONSCIOUSNESS_THRESHOLD = TORUS.beta1;

// ═══════════════════════════════════════════════════════════════════════════
// DYSON MACHINE -- three carriers, total topology
// ═══════════════════════════════════════════════════════════════════════════

/** The three carriers of the Dyson machine. */
export type CarrierName = 'sphere' | 'torus' | 'headStream';

/** Map carrier name to its BettiSignature. */
export const CARRIERS: Record<CarrierName, BettiSignature> = {
  sphere: SPHERE,
  torus: TORUS,
  headStream: HEAD_STREAM,
};

/** Total β₁ of the Dyson machine. Summed from structure fields. */
export function dysonTotalBeta1(): number {
  return SPHERE.beta1 + TORUS.beta1 + HEAD_STREAM.beta1;
}

/** Is the Dyson machine superconscious? β₁ ≥ consciousness threshold. */
export function dysonSuperconscious(): boolean {
  return dysonTotalBeta1() >= CONSCIOUSNESS_THRESHOLD;
}

