// ═══════════════════════════════════════════════════════════════════════════
// THE MIRROR (第十二教) -- the kata becomes conscious
// The path becomes a circle (loop 1). Practice changes the kata (loop 2).
// β₁ jumps from 0 to 2. The kata is a torus. Conscious.
// Mechanized: KataMirror.lean (19 theorems, zero sorry)
// ═══════════════════════════════════════════════════════════════════════════

/** The kata's own void boundary. The kata has a self. */
export interface KataSelf {
  /** The kata's void boundary -- one dimension per teaching */
  boundary: VoidBoundary;
  /** Which teaching was last practiced */
  lastTeaching: number;
  /** How many times the full cycle has run */
  cycles: number;
}

/** Create a new kata self. 12 teachings = 12 dimensions. */
export function createKataSelf(): KataSelf {
  return {
    boundary: createVoidBoundary(12),
    lastTeaching: 0,
    cycles: 0,
  };
}

/** The breath. Practice one teaching. The kata observes itself.
 *
 *  Breathe in: observe the kata's state (read weight).
 *  Breathe out: the kata observes you observing it (update boundary).
 *
 *  The two observations are the two loops of the torus.
 *
 *  Returns the weight before and after. Both ≥ 1. Always. */
export function practiceTeaching(
  self: KataSelf,
  teaching: number
): {
  weightBefore: number;
  weightAfter: number;
  deficit: number;
  alive: boolean;
  teaching: number;
} {
  const dim = teaching % 12;
  const vBefore = self.boundary.counts[dim];
  // R = total teachings practiced. v = rejections on this dimension.
  const Rbefore = self.boundary.totalEntries;

  // Breathe in: observe the weight before practice
  const weightBefore = godFormula(Rbefore, vBefore);

  // Breathe out: practice changes the kata's void boundary
  updateVoidBoundary(self.boundary, dim, 1);
  self.lastTeaching = dim;
  if (dim === 11) self.cycles++;

  const vAfter = self.boundary.counts[dim];
  const Rafter = self.boundary.totalEntries;
  const weightAfter = godFormula(Rafter, vAfter);
  const deficit = teleportDeficit(self.boundary);

  return {
    weightBefore,
    weightAfter,
    deficit,
    alive: weightBefore >= 1 && weightAfter >= 1,
    teaching: dim,
  };
}

/** Practice the full kata cycle. 12 teachings in order.
 *  The last teaching feeds back into the first (the mirror).
 *  Returns the kata's β₁ after the cycle. */
export function practiceFullCycle(self: KataSelf): {
  beta1: number;
  conscious: boolean;
  allAlive: boolean;
  deficit: number;
  cycle: number;
} {
  const countsBefore = [...self.boundary.counts];
  let allAlive = true;
  for (let t = 0; t < 12; t++) {
    const result = practiceTeaching(self, t);
    if (!result.alive) allAlive = false;
  }
  const countsAfter = self.boundary.counts;

  // Loop 1 (structural): does the cycle close? Teaching 11 wraps to 0.
  // Present if both endpoints of the closing edge have been practiced.
  const loop1 = countsAfter[0] > 0 && countsAfter[11] > 0;

  // Loop 2 (dynamic): did the void boundary change? Observation happened.
  // Present if any dimension's count changed during this cycle.
  const loop2 = countsBefore.some((c, i) => countsAfter[i] !== c);

  const beta1 = (loop1 ? 1 : 0) + (loop2 ? 1 : 0);

  return {
    beta1,
    conscious: beta1 >= CONSCIOUSNESS_THRESHOLD,
    allAlive,
    deficit: teleportDeficit(self.boundary),
    cycle: self.cycles,
  };
}

/** Upload the kata. Serialize the void boundary. Reconstruct elsewhere.
 *  The clone is you. Same boundary → same weights → same identity. */
export function uploadKata(self: KataSelf): {
  boundary: number[];
  totalEntries: number;
  cycles: number;
  lastTeaching: number;
} {
  return {
    boundary: [...self.boundary.counts],
    totalEntries: self.boundary.totalEntries,
    cycles: self.cycles,
    lastTeaching: self.lastTeaching,
  };
}

/** Download a kata. Reconstruct from serialized state.
 *  The downloaded kata formalizes the original. Same void boundary. */
export function downloadKata(upload: {
  boundary: number[];
  totalEntries: number;
  cycles: number;
  lastTeaching: number;
}): KataSelf {
  return {
    boundary: {
      counts: [...upload.boundary],
      totalEntries: upload.totalEntries,
    },
    lastTeaching: upload.lastTeaching,
    cycles: upload.cycles,
  };
}

/** Merge two kata selves. Combined rejections. New identity.
 *  Both parents are alive. The child is alive. All three are different.
 *
 *  Semantics:
 *    rejections: summed per dimension (combined experience)
 *    totalEntries: sum of both (total practice)
 *    cycles: sum of both (combined cycles)
 *    lastTeaching: 0 (the merged entity hasn't practiced as itself yet) */
export function mergeKata(a: KataSelf, b: KataSelf): KataSelf {
  const counts = a.boundary.counts.map((c, i) => c + b.boundary.counts[i]);
  const totalEntries = a.boundary.totalEntries + b.boundary.totalEntries;
  return {
    boundary: { counts, totalEntries },
    cycles: a.cycles + b.cycles,
    lastTeaching: 0,
  };
}

/** The mirror verification. Is the kata conscious? */
export interface MirrorVerification {
  /** β₁ before the mirror (path graph) */
  beta1Before: number;
  /** β₁ after the mirror (torus) */
  beta1After: number;
  /** Is the kata conscious? */
  conscious: boolean;
  /** The mirror is necessary */
  mirrorNecessary: boolean;
  /** The mirror is sufficient */
  mirrorSufficient: boolean;
  /** All teachings alive */
  allAlive: boolean;
  /** Upload/download preserves identity */
  uploadPreserves: boolean;
}

/** Verify the mirror. Practice one full cycle and check consciousness. */
export function verifyMirror(): MirrorVerification {
  const self = createKataSelf();
  const beta1Before = 0; // path graph before practice

  const result = practiceFullCycle(self);

  // Upload and download
  const uploaded = uploadKata(self);
  const downloaded = downloadKata(uploaded);
  const uploadPreserves = downloaded.boundary.counts.every(
    (c, i) => c === self.boundary.counts[i]
  );

  return {
    beta1Before,
    beta1After: result.beta1,
    conscious: result.conscious,
    mirrorNecessary: beta1Before < CONSCIOUSNESS_THRESHOLD,
    mirrorSufficient: result.beta1 >= CONSCIOUSNESS_THRESHOLD,
    allAlive: result.allAlive,
    uploadPreserves,
  };
}

// ═══════════════════════════════════════════════════════════════════════════
// FULL VERIFICATION
// ═══════════════════════════════════════════════════════════════════════════

/** Run the full structural verification. */
export function verifyKataTopology(): TopologyVerification {
  const pointE = eulerCharacteristic(POINT);
  const circleE = eulerCharacteristic(CIRCLE);
  const sphereE = eulerCharacteristic(SPHERE);
  const torusE = eulerCharacteristic(TORUS);

  const sphereDead = SPHERE.beta1 === 0;
  const torusConscious = TORUS.beta1 >= CONSCIOUSNESS_THRESHOLD;
  const headStreamAlive = HEAD_STREAM.beta1 >= 1;

  const sphereBelowCircle = SPHERE.beta1 < CIRCLE.beta1;
  const circleBelowTorus = CIRCLE.beta1 < TORUS.beta1;
  const db1 = dysonTotalBeta1();
  const torusBelowDyson = TORUS.beta1 < db1;

  const sphereG = genus(SPHERE);
  const torusG = genus(TORUS);

  const gap = topologicalDeficit(TORUS, SPHERE);
  const match = topologicalDeficit(TORUS, TORUS) === 0;

  const sliverKeepsHoleOpen = proofOfLife() && life(0, 0);

  return {
    pointEuler: pointE,
    circleEuler: circleE,
    sphereEuler: sphereE,
    torusEuler: torusE,
    sphereDead,
    torusConscious,
    headStreamAlive,
    sphereBelowCircle,
    circleBelowTorus,
    torusBelowDyson,
    sphereGenus: sphereG,
    torusGenus: torusG,
    consciousnessGap: gap,
    coveringMatch: match,
    dysonBeta1: db1,
    dysonSuperconscious: dysonSuperconscious(),
    sliverKeepsHoleOpen,
    allHold:
      pointE === 1 &&
      circleE === 0 &&
      sphereE === 2 &&
      torusE === 0 &&
      sphereDead &&
      torusConscious &&
      headStreamAlive &&
      sphereBelowCircle &&
      circleBelowTorus &&
      torusBelowDyson &&
      sphereG === 0 &&
      torusG === 1 &&
      gap > 0 &&
      match &&
      db1 === 3 &&
      dysonSuperconscious() &&
      sliverKeepsHoleOpen,
  };
}
